import type { Route } from './+types/home';
import { useEffect, useState, cloneElement, type ReactElement, type ReactNode } from 'react';
import { useNavigate } from 'react-router';
import { useLocalUser } from '../hooks/useLocalUser';
import { signInWithEduAi } from '../lib/auth-client';
import type { Role } from '../lib/types';
import { 
  BookOpen, 
  BrainCircuit, 
  GraduationCap, 
  LayoutDashboard, 
  Library, 
  LineChart, 
  Sparkles, 
  Zap 
} from 'lucide-react';

export function meta({}: Route.MetaArgs) {
  return [
    { title: 'AI Tutor - Welcome' },
    { name: 'description', content: 'Sign in to AI Tutor with your EduAI account' },
  ];
}

function routeForRole(role: Role) {
  if (role === 'STUDENT') return '/student';
  if (role === 'PROFESSOR') return '/instructor';
  if (role === 'TA') return '/unsupported-role';
  return '/admin';
}

function extractErrorMessage(error: unknown) {
  if (!(error instanceof Error)) {
    return 'Could not start EduAI sign-in';
  }

  try {
    const parsed = JSON.parse(error.message);
    if (typeof parsed?.message === 'string' && parsed.message.trim()) {
      return parsed.message;
    }
    if (typeof parsed?.error === 'string' && parsed.error.trim()) {
      return parsed.error;
    }
  } catch {
    // Fall back to the raw message when the backend returns plain text.
  }

  return error.message || 'Could not start EduAI sign-in';
}

export default function Home() {
  const navigate = useNavigate();
  const { user, isInitializing } = useLocalUser();
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    if (!user) return;
    navigate(routeForRole(user.role), { replace: true });
  }, [navigate, user]);

  useEffect(() => {
    if (typeof window === 'undefined') return;
    const params = new URLSearchParams(window.location.search);
    if (params.get('authError') === 'eduai_sign_in_failed') {
      setError('EduAI sign-in did not complete. Please try again.');
    }
  }, []);

  const onSignIn = async () => {
    setLoading(true);
    setError('');

    try {
      await signInWithEduAi();
    } catch (err) {
      setError(extractErrorMessage(err));
      setLoading(false);
      return;
    } finally {
      // Full-page redirect keeps this from usually running, but it protects the button on failure.
      setLoading(false);
    }
  };

  // Loading State
  if (isInitializing || user) {
    return (
      <main className="relative min-h-dvh overflow-hidden bg-background flex items-center justify-center">
        <div className="absolute inset-0 dots-pattern opacity-50" />
        <div className="relative z-10 flex flex-col items-center gap-4">
          <div className="relative h-16 w-16">
            <div className="absolute inset-0 rounded-full border-4 border-primary/20" />
            <div className="absolute inset-0 rounded-full border-4 border-primary border-t-transparent animate-spin" />
            <BrainCircuit className="absolute inset-0 m-auto h-6 w-6 text-primary animate-pulse" />
          </div>
          <div className="font-display text-lg font-medium text-muted-foreground animate-pulse">
            Initializing your workspace...
          </div>
        </div>
      </main>
    );
  }

  return (
    <main className="relative min-h-dvh w-full overflow-hidden bg-background text-foreground lg:grid lg:grid-cols-2">

      {/* LEFT COLUMN: Immersive Visuals */}
      <div className="relative hidden lg:flex flex-col justify-between p-12 overflow-hidden bg-primary/5 dark:bg-primary/5">
        {/* Background Elements */}
        <div className="absolute inset-0 dots-pattern opacity-30" />
        <div className="absolute top-[-20%] left-[-10%] h-[500px] w-[500px] rounded-full bg-primary/10 blur-[100px] animate-pulse-soft" />
        <div className="absolute bottom-[-10%] right-[-10%] h-[400px] w-[400px] rounded-full bg-accent/10 blur-[80px] animate-float delay-700" />

        {/* Header Logo Area */}
        <div className="relative z-10 flex items-center gap-3 animate-fade-down">
          <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-primary text-primary-foreground shadow-lg shadow-primary/20">
            <GraduationCap className="h-6 w-6" />
          </div>
          <span className="font-display text-xl font-bold tracking-tight">AI Tutor</span>
        </div>

        {/* Central Visual Composition */}
        <div className="relative z-10 flex-1 flex items-center justify-center">
          <div className="relative w-full max-w-md aspect-square">
            {/* Center Node */}
            <div className="absolute inset-0 m-auto h-32 w-32 rounded-3xl bg-card border border-border/50 shadow-2xl flex items-center justify-center z-20 animate-scale-in">
              <BrainCircuit className="h-16 w-16 text-primary" />
            </div>

            {/* Orbiting Nodes */}
            <div className="absolute top-[10%] left-[20%] animate-float delay-0 z-20">
              <FloatingNode icon={<Library className="h-5 w-5" />} label="Curriculum" />
            </div>
            <div className="absolute top-[20%] right-[10%] animate-float delay-300 z-20">
              <FloatingNode icon={<Sparkles className="h-5 w-5" />} label="AI Insights" />
            </div>
            <div className="absolute bottom-[20%] left-[10%] animate-float delay-500 z-20">
              <FloatingNode icon={<LineChart className="h-5 w-5" />} label="Progress" />
            </div>
            <div className="absolute bottom-[10%] right-[20%] animate-float delay-700 z-20">
              <FloatingNode icon={<LayoutDashboard className="h-5 w-5" />} label="Dashboard" />
            </div>

            {/* Connecting Lines (Decorative) */}
            <svg className="absolute inset-0 h-full w-full pointer-events-none opacity-20 text-primary z-10" viewBox="0 0 400 400">
               <path d="M200 200 L120 100" stroke="currentColor" strokeWidth="2" strokeDasharray="4 4" />
               <path d="M200 200 L320 120" stroke="currentColor" strokeWidth="2" strokeDasharray="4 4" />
               <path d="M200 200 L80 280" stroke="currentColor" strokeWidth="2" strokeDasharray="4 4" />
               <path d="M200 200 L280 320" stroke="currentColor" strokeWidth="2" strokeDasharray="4 4" />
            </svg>
          </div>
        </div>

        {/* Testimonial / Footer Quote */}
        <div className="relative z-10 animate-fade-up delay-300">
          <blockquote className="border-l-4 border-primary pl-4 italic text-muted-foreground max-w-md">
            "Education is not the filling of a pail, but the lighting of a fire."
          </blockquote>
          <cite className="mt-2 block text-sm font-semibold not-italic text-foreground">- W.B. Yeats</cite>
        </div>
      </div>

      {/* RIGHT COLUMN: Auth & Context */}
      <div className="relative flex flex-col items-center justify-center p-6 sm:p-12 lg:p-24 bg-background">
         <div className="absolute inset-0 dots-pattern opacity-50 lg:hidden" />

         <div className="w-full max-w-lg space-y-10 z-10">
            {/* Mobile Header (Only visible on small screens) */}
            <div className="lg:hidden flex items-center gap-3 mb-8 animate-fade-down">
              <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-primary text-primary-foreground shadow-lg shadow-primary/20">
                <GraduationCap className="h-6 w-6" />
              </div>
              <span className="font-display text-xl font-bold tracking-tight">AI Tutor</span>
            </div>

            <div className="space-y-4 text-center lg:text-left animate-fade-up">
              <div className="inline-flex items-center gap-2 rounded-full border border-primary/20 bg-primary/5 px-3 py-1 text-xs font-semibold text-primary">
                <Sparkles className="h-3 w-3" />
                <span>Next Gen Learning</span>
              </div>
              <h1 className="font-display text-4xl font-bold tracking-tight text-foreground sm:text-5xl lg:text-6xl leading-[1.1]">
                Master any subject <br />
                <span className="text-gradient">with AI guidance</span>
              </h1>
              <p className="text-lg text-muted-foreground max-w-md mx-auto lg:mx-0">
                Experience a personalized learning journey that adapts to your pace. 
                Get real-time feedback, deep insights, and structured curriculum.
              </p>
            </div>

            {/* Auth Card */}
            <div className="panel-glass rounded-2xl p-8 shadow-xl border border-border/50 animate-scale-in delay-200">
              <div className="mb-6">
                <h2 className="text-xl font-semibold font-display text-foreground flex items-center gap-2">
                  <span className="flex h-8 w-8 items-center justify-center rounded-lg bg-secondary text-foreground">
                    <BookOpen className="h-4 w-4" />
                  </span>
                  Welcome back
                </h2>
                <p className="text-sm text-muted-foreground mt-1 ml-10">
                  Sign in to continue your progress
                </p>
              </div>

              {error && (
                <div className="mb-6 animate-fade-in flex items-start gap-3 rounded-lg border border-destructive/20 bg-destructive/5 p-3 text-sm text-destructive">
                   <div className="mt-0.5">
                     <svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                     </svg>
                   </div>
                   <p>{error}</p>
                </div>
              )}

              <div className="space-y-4">
                <button
                  type="button"
                  onClick={onSignIn}
                  disabled={loading}
                  className="btn-primary w-full group relative overflow-hidden"
                >
                  <div className="relative z-10 flex items-center justify-center gap-2">
                    {loading ? (
                      <>
                        <div className="h-4 w-4 animate-spin rounded-full border-2 border-current border-t-transparent" />
                        <span>Connecting...</span>
                      </>
                    ) : (
                      <>
                        <span>Sign in with EduAI</span>
                        <Zap className="h-4 w-4 transition-transform group-hover:scale-110" />
                      </>
                    )}
                  </div>
                  {/* Button Glow Effect */}
                  <div className="absolute inset-0 -translate-x-full group-hover:animate-shimmer bg-gradient-to-r from-transparent via-white/20 to-transparent" />
                </button>

