        <div className="absolute top-[-20%] left-[-10%] h-[500px] w-[500px] rounded-full bg-primary/10 blur-[100px] animate-pulse-soft" />
        <div className="absolute bottom-[-10%] right-[-10%] h-[400px] w-[400px] rounded-full bg-accent/10 blur-[80px] animate-float delay-700" />

        {/* Header Logo Area */}
        <div className="relative z-10 flex items-center gap-3 animate-fade-down">
          <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-primary text-primary-foreground shadow-lg shadow-primary/20">
            <GraduationCap className="h-6 w-6" />
          </div>
          <span className="font-display text-xl font-bold tracking-tight">AI Tutor</span>
        </div>

        {/* Central Visual Composition */}
        <div className="relative z-10 flex-1 flex items-center justify-center">
          <div className="relative w-full max-w-md aspect-square">
            {/* Center Node */}
