            </svg>
          </div>
        </div>

        {/* Testimonial / Footer Quote */}
        <div className="relative z-10 animate-fade-up delay-300">
          <blockquote className="border-l-4 border-primary pl-4 italic text-muted-foreground max-w-md">
            "Education is not the filling of a pail, but the lighting of a fire."
          </blockquote>
          <cite className="mt-2 block text-sm font-semibold not-italic text-foreground">- W.B. Yeats</cite>
        </div>
      </div>

      {/* RIGHT COLUMN: Auth & Context */}
      <div className="relative flex flex-col items-center justify-center p-6 sm:p-12 lg:p-24 bg-background">
