              <h1 className="font-display text-4xl font-bold tracking-tight text-foreground sm:text-5xl lg:text-6xl leading-[1.1]">
                Master any subject <br />
                <span className="text-gradient">with AI guidance</span>
              </h1>
              <p className="text-lg text-muted-foreground max-w-md mx-auto lg:mx-0">
                Experience a personalized learning journey that adapts to your pace. 
                Get real-time feedback, deep insights, and structured curriculum.
              </p>
            </div>

