                  <span className="flex h-8 w-8 items-center justify-center rounded-lg bg-secondary text-foreground">
                    <BookOpen className="h-4 w-4" />
                  </span>
                  Welcome back
                </h2>
                <p className="text-sm text-muted-foreground mt-1 ml-10">
                  Sign in to continue your progress
                </p>
              </div>

              {error && (
                <div className="mb-6 animate-fade-in flex items-start gap-3 rounded-lg border border-destructive/20 bg-destructive/5 p-3 text-sm text-destructive">
                   <div className="mt-0.5">
                     <svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                     </svg>
                   </div>
                   <p>{error}</p>
                </div>
              )}

              <div className="space-y-4">
                <button
                  type="button"
                  onClick={onSignIn}
                  disabled={loading}
                  className="btn-primary w-full group relative overflow-hidden"
                >
                  <div className="relative z-10 flex items-center justify-center gap-2">
                    {loading ? (
